CREATE PROC [dbo].[TR_DONDATHANG_CHITIET_Ver2_Insert]
(
	@maddh nvarchar(200),
    @chitiet nvarchar(200),
    @tenchitiet nvarchar(200),
    @soluong decimal(18,3),
    @dvt nvarchar(50),
    @sl_danhan decimal(18,3),
    @sl_conlai decimal(18,3),
    @dongia decimal(18,3),
    @thanhtien decimal(18,3),
	@donhang nvarchar(max),
    @ghichu nvarchar(max),
    @create_by nvarchar(200)
)
AS

DECLARE @CNT NVARCHAR(MAX);
DECLARE @SUDUNGCHO NVARCHAR(MAX);
 
SELECT @CNT = chitiet, @SUDUNGCHO = donhang
FROM tr_dondathang_chitiet
WHERE maddh = @maddh
	AND chitiet = @chitiet
	and active = 1;

IF @CNT IS NULL
BEGIN
INSERT INTO tr_dondathang_chitiet
      (
          maddh,
          chitiet,
          tenchitiet,
          soluong,
          dvt,
          sl_danhan,
          sl_conlai,
          dongia,
          thanhtien,
		  donhang,
          ghichu,
          create_date,
          create_by
      )
VALUES (
          @maddh,
          @chitiet,
          @tenchitiet,
          @soluong,
          @dvt,
          @sl_danhan,
          @sl_conlai,
          @dongia,
          @thanhtien,
		  @donhang,
          @ghichu,
          getdate(),
          @create_by
       )
END

IF @CNT IS NOT NULL
BEGIN
	
	IF @SUDUNGCHO != @donhang
	BEGIN
		IF @SUDUNGCHO IS NULL
			SET @SUDUNGCHO = @donhang;
		ELSE
			SET @SUDUNGCHO = CONCAT(@SUDUNGCHO, ', ', @donhang);

		IF RIGHT(dbo.TRIM(@SUDUNGCHO), 1) = ','
			SET @SUDUNGCHO = LEFT(dbo.TRIM(@SUDUNGCHO), LEN(@SUDUNGCHO)-1);

		UPDATE tr_dondathang_chitiet
		SET donhang = @SUDUNGCHO
		WHERE maddh = @maddh AND chitiet = @chitiet and active = 1 
	END
	
	
	IF @ghichu IS NOT NULL OR @ghichu <> ''
	BEGIN
		UPDATE tr_dondathang_chitiet
		SET soluong = soluong + @soluong, ghichu = @ghichu
		WHERE maddh = @maddh AND chitiet = @chitiet and active = 1
	END
	ELSE
	BEGIN
		UPDATE tr_dondathang_chitiet
		SET soluong = soluong + @soluong
		WHERE maddh = @maddh AND chitiet = @chitiet and active = 1
	END

